SELECT SUM(payment_amount) AS total_payment_amount
FROM payments
WHERE project_id IN (SELECT project_id FROM projects WHERE status = 'active');

SELECT SUM(payment_amount) AS total_payment_amount
FROM payments
WHERE project_id = (SELECT project_id FROM projects WHERE project_name = 'Project A');

SELECT material_id, price, price_date
FROM material_prices
WHERE price_date = '2023-01-01';
